SELECT *
FROM twitter_users
WHERE total_tweets > 500 AND verified = 1 AND location = 'United States';

SELECT ut.user_id, ut.topic_name, pa.party_affiliation_score
FROM user_topics ut
JOIN party_affiliations pa ON ut.user_id = pa.user_id;

SELECT AVG(t1.followers_per_day / (t2.twitter_age / 365.0)) AS average_followers_gained_per_day
FROM tweet_metrics AS t1
JOIN twitter_users AS t2 ON t1.user_id = t2.user_id;

SELECT user_id, 
       FIRST_VALUE(topic_name) OVER (PARTITION BY user_id ORDER BY topic_weight DESC) AS most_prominent_topic
FROM user_topics;

SELECT SUM(retweet_count), SUM(favorite_count), SUM(reply_count), SUM(quote_count)
FROM tweets
WHERE user_id = (SELECT user_id FROM twitter_users WHERE username = 'desired_username');

SELECT username, total_tweets
FROM twitter_users
WHERE followers = (
    SELECT MAX(followers)
    FROM twitter_users
);

SELECT tu.username, pa.party_affiliation_score
FROM twitter_users tu
JOIN party_affiliations pa ON tu.user_id = pa.user_id
WHERE pa.party_affiliation_score > (
    SELECT AVG(party_affiliation_score) FROM party_affiliations
);

SELECT username, followers, total_tweets
FROM twitter_users
ORDER BY total_tweets DESC;

SELECT language, COUNT(*) AS user_count
FROM twitter_users
GROUP BY language;
